// orchestrator example
interface SagaStep { execute: ()=>Promise<void>; compensate: ()=>Promise<void>; }
async function runSaga(steps:SagaStep[]) {
  const completed:SagaStep[]=[];
  try{
    for(const s of steps){await s.execute();completed.push(s);}
  }catch(err){
    for(const s of completed.reverse()){
      try{await s.compensate();}catch(c){alerter.error('compensation failed',{c});}
    }
    throw err;
  }
}

