import {Pool} from 'pg';
import {S3Client,PutObjectCommand} from '@aws-sdk/client-s3';
import parquet from 'parquetjs';
const pool=new Pool({...});
const s3=new S3Client({});

const cutoff=new Date(Date.now()-90*24*3600*1000);
const schema=new parquet.ParquetSchema({id:{type:'INT64'},actor_id:{type:'UTF8'},action:{type:'UTF8'},at:{type:'TIMESTAMP_MILLIS'}});

async function archiveDay(day:Date){
  const rows=(await pool.query("SELECT * FROM audit_log WHERE at::date = $1",[day])).rows;
  if(!rows.length)return;
  const file=`/tmp/${day.toISOString().slice(0,10)}.parquet`;
  const writer=await parquet.ParquetWriter.openFile(schema,file);
  for(const r of rows)await writer.appendRow(r);
  await writer.close();
  await s3.send(new PutObjectCommand({Bucket:'audit-archive',Key:`year=${day.getFullYear()}/${day.toISOString().slice(0,10)}.parquet`,Body:require('fs').createReadStream(file)}));
  await pool.query("DELETE FROM audit_log WHERE at::date = $1",[day]);
}

