CREATE OR REPLACE FUNCTION transfer_credits(p_from UUID, p_to UUID, p_amount BIGINT)
RETURNS BOOLEAN AS $$
DECLARE balance BIGINT;
BEGIN
  SELECT amount INTO balance FROM accounts WHERE id = p_from FOR UPDATE;
  IF balance < p_amount THEN RAISE EXCEPTION 'insufficient_funds'; END IF;
  UPDATE accounts SET amount = amount - p_amount WHERE id = p_from;
  UPDATE accounts SET amount = amount + p_amount WHERE id = p_to;
  RETURN TRUE;
END;
$$ LANGUAGE plpgsql;

