// backfill
async function backfill(){
  while(true){
    const r=await pgPool.query("SELECT id, name, file_data FROM files WHERE s3_key IS NULL LIMIT 100");
    if(!r.rowCount)break;
    for(const f of r.rows){
      const key=`uploads/${f.id}/${f.name}`;
      await s3.send(new PutObjectCommand({Bucket:'files',Key:key,Body:f.file_data}));
      await pgPool.query('UPDATE files SET s3_key=$1 WHERE id=$2', [key, f.id]);
    }
  }
}

