-- chunked recompute
DO $$
DECLARE cursor_id BIGINT := 0; rows INT;
BEGIN
  LOOP
    WITH batch AS (
      SELECT o.id, COALESCE(SUM(oi.qty * oi.price_cents), 0) AS new_total
      FROM orders o LEFT JOIN order_items oi ON oi.order_id = o.id
      WHERE o.id > cursor_id GROUP BY o.id ORDER BY o.id LIMIT 5000
    )
    UPDATE orders SET total_cents = b.new_total FROM batch b WHERE orders.id = b.id
    RETURNING orders.id INTO cursor_id;
    GET DIAGNOSTICS rows = ROW_COUNT;
    EXIT WHEN rows = 0;
    PERFORM pg_sleep(0.1);
  END LOOP;
END $$;

